    void checkPositionIndex(int index) {
        if (!isPositionIndex(index)) {
            throw out_of_range("Index: " + to_string(index) + ", size_: " + to_string(size_));
        }
    }

    // 返回 index 对应的 Node
    // 注意：请保证传入的 index 是合法的
    Node* getNode(int index) {
        Node* p = head->next;
        for (int i = 0; i < index; i++) {
            p = p->next;
        }
        return p;
    }
};

